// Compliance.js
import React, { useState, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import axios from 'axios';
import { Upload } from 'lucide-react';

export default function Compliance() {
  const [mode,    setMode]    = useState('text');  // 'text' or 'upload'
  const [text,    setText]    = useState('');
  const [file,    setFile]    = useState(null);
  const [loading, setLoading] = useState(false);
  const [result,  setResult]  = useState(null);
  const [error,   setError]   = useState('');

  const onDrop = useCallback(accepted => {
    if (accepted[0]) { setFile(accepted[0]); setResult(null); }
  }, []);
  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop, accept: { 'application/pdf': ['.pdf'] }, maxFiles: 1,
  });

  const handleCheck = async () => {
    setLoading(true); setError(''); setResult(null);
    try {
      let res;
      if (mode === 'text') {
        res = await axios.post('/api/compliance', { text });
      } else {
        const form = new FormData();
        form.append('file', file);
        res = await axios.post('/api/compliance/upload', form);
      }
      setResult(res.data);
    } catch (e) {
      setError(e.response?.data?.detail || 'Check failed.');
    }
    setLoading(false);
  };

  const scoreClass = result ? (
    result.score >= 90 ? 'score-a' :
    result.score >= 70 ? 'score-b' :
    result.score >= 50 ? 'score-c' : 'score-f'
  ) : '';

  return (
    <div>
      <h1 className="section-title" style={{ fontSize: '1.4rem', marginBottom: 8 }}>
        ⚖️ BNS Compliance Checker
      </h1>
      <p className="text-grey mb-6">
        Check if your legal document uses outdated IPC/CrPC sections.
        Get the correct BNS 2023 / BNSS 2023 equivalents and a compliance score.
      </p>

      <div className="card mb-4">
        <div style={{ display: 'flex', gap: 8, marginBottom: 20 }}>
          <button
            className={`btn ${mode === 'text'   ? 'btn-primary' : 'btn-outline'}`}
            onClick={() => setMode('text')}
          >Paste Text</button>
          <button
            className={`btn ${mode === 'upload' ? 'btn-primary' : 'btn-outline'}`}
            onClick={() => setMode('upload')}
          >Upload PDF</button>
        </div>

        {mode === 'text' ? (
          <textarea
            value={text}
            onChange={e => setText(e.target.value)}
            placeholder="Paste any legal text, FIR, petition, or notice here..."
            style={{
              width: '100%', minHeight: 200, padding: 12,
              border: '1px solid var(--border)', borderRadius: 'var(--radius)',
              fontSize: '0.9rem', fontFamily: 'inherit', resize: 'vertical',
              outline: 'none',
            }}
          />
        ) : (
          <div {...getRootProps()} className={`upload-zone ${isDragActive ? 'drag-active' : ''}`}>
            <input {...getInputProps()} />
            <div className="upload-zone-icon"><Upload size={36} /></div>
            <div className="upload-zone-text">
              {file
                ? <strong style={{ color: 'var(--navy)' }}>{file.name}</strong>
                : <><strong>Click to upload PDF</strong> or drag and drop</>
              }
            </div>
          </div>
        )}

        <button
          className="btn btn-primary mt-4"
          onClick={handleCheck}
          disabled={loading || (mode === 'text' ? !text.trim() : !file)}
        >
          {loading ? '⏳ Checking...' : '🔍 Check Compliance'}
        </button>
        {error && <div style={{ color: 'var(--red)', marginTop: 8, fontSize: '0.9rem' }}>⚠️ {error}</div>}
      </div>

      {result && (
        <div className="card">
          <div style={{ display: 'flex', gap: 24, alignItems: 'flex-start', flexWrap: 'wrap' }}>
            <div className="score-display" style={{ minWidth: 140 }}>
              <div className={`score-circle ${scoreClass}`}>
                <div>{result.score}</div>
                <div style={{ fontSize: '1rem' }}>{result.grade}</div>
              </div>
              <div style={{ fontSize: '0.85rem', color: 'var(--grey)' }}>BNS Compliance</div>
            </div>

            <div style={{ flex: 1 }}>
              <div className="section-title">Analysis</div>
              <p style={{ marginBottom: 16, fontSize: '0.9rem' }}>{result.note}</p>

              {result.mappings?.length > 0 && (
                <>
                  <div className="section-title" style={{ fontSize: '0.95rem' }}>IPC → BNS Corrections</div>
                  {result.mappings.map((m, i) => (
                    <div key={i} style={{
                      display: 'flex', gap: 12, alignItems: 'center',
                      padding: '8px 12px', marginBottom: 6,
                      background: m.new === 'ABOLISHED' ? 'var(--ltred)' : 'var(--ltgreen)',
                      borderRadius: 'var(--radius)',
                      fontSize: '0.88rem',
                    }}>
                      <span style={{ fontWeight: 600 }}>{m.old}</span>
                      <span style={{ color: 'var(--grey)' }}>→</span>
                      <span style={{
                        fontWeight: 600,
                        color: m.new === 'ABOLISHED' ? 'var(--red)' : 'var(--green)',
                      }}>{m.new}</span>
                      <span style={{ color: 'var(--grey)', fontSize: '0.82rem' }}>({m.name})</span>
                    </div>
                  ))}
                </>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
